mapper.select:
select tui.* from t_user_info tui

    tui.deleted = 0
     and tui.user_id = #{userId}
     and tui.has_service_center = #{hasServiceCenter}
     and tui.account like concat('%', #{account}, '%')
     and tui.user_code = #{userCode}
     and tui.tr_recharge_address like concat('%', #{email}, '%')
     and tui.game_level = #{gameLevel}

        and GREATEST(game_level, min_game_level) = #{finaGameLevel}

     and tui.min_game_level = #{minGameLevel}
     and tui.invite_user_code = #{inviteUserCode}
     and tui.invite_user_id = #{inviteUserId}
     and tui.status = #{status}
     and tui.is_valid = #{isValid}
     and tui.sub_num = #{subNum}
     and tui.valid_sub_num = #{validSubNum}
     and tui.umbrella_num = #{umbrellaNum}
     and tui.valid_umbrella_num = #{validUmbrellaNum}
     and tui.performance = #{performance}
     and tui.umbrella_performance = #{umbrellaPerformance}
     and tui.withdrawal_open_or_close = #{withdrawalOpenOrClose}
     and create_time between #{params.beginCreateTime} and #{params.endCreateTime}

order by tui.user_id desc

select a.* from t_user_info a
inner join t_user_relation b on a.user_id = b.pos_user_id and b.par_user_id = #{params.topUserId} and b.distance > 0

     and a.user_id = #{userId}
     and a.has_service_center = #{hasServiceCenter}
     and a.account like concat('%', #{account}, '%')
     and a.user_code = #{userCode}
     and a.tr_recharge_address like concat('%', #{email}, '%')
     and a.game_level = #{gameLevel}
     and a.min_game_level = #{minGameLevel}
     and a.invite_user_code = #{inviteUserCode}
     and a.invite_user_id = #{inviteUserId}
     and a.status = #{status}
     and a.is_valid = #{isValid}
     and a.sub_num = #{subNum}
     and a.valid_sub_num = #{validSubNum}
     and a.umbrella_num = #{umbrellaNum}
     and a.valid_umbrella_num = #{validUmbrellaNum}
     and a.performance = #{performance}
     and a.umbrella_performance = #{umbrellaPerformance}
     and a.withdrawal_open_or_close = #{withdrawalOpenOrClose}

order by a.user_id desc

SELECT a.user_id, a.account, a.performance, a.game_level, a.sub_num, a.umbrella_num, a.valid_umbrella_num, a.umbrella_performance, a.create_time FROM t_user_info a INNER JOIN t_user_relation b ON a.user_id = b.pos_user_id WHERE b.active_flag = 1 AND b.par_user_id = #{userId} AND b.distance > 0
AND game_level = #{level}
ORDER BY a.user_id DESC LIMIT 500
